438:     private double distancePointToSegment(double px, double pz, double ax, double az, double bx, double bz) {
439:         double dx = bx - ax;
440:         double dz = bz - az;
441:         double lengthSquared = dx * dx + dz * dz;
442:         if (lengthSquared == 0) {
443:             double pointDx = px - ax;
444:             double pointDz = pz - az;
445:             return Math.sqrt(pointDx * pointDx + pointDz * pointDz);
446:         }
447: 
448:         double t = ((px - ax) * dx + (pz - az) * dz) / lengthSquared;
449:         t = Math.max(0, Math.min(1, t));
450:         double projX = ax + t * dx;
451:         double projZ = az + t * dz;
452:         double distX = px - projX;
453:         double distZ = pz - projZ;
454:         return Math.sqrt(distX * distX + distZ * distZ);
455:     }
