package com.example.village.building;

import org.bukkit.configuration.ConfigurationSection;
import org.bukkit.configuration.file.YamlConfiguration;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import java.io.File;
import java.util.Set;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Verifiziert, dass max_instances-Werte in buildings.yml korrekt konfiguriert sind.
 *
 * Dorfzentrum darf nur 1 Mal gebaut werden. Andere Gebäude dürfen kein
 * unbeabsichtigtes Limit haben (max_instances fehlt oder ist -1).
 */
class BuildingConfigMaxInstancesTest {

    private static YamlConfiguration config;

    @BeforeAll
    static void loadConfig() {
        File configFile = new File("resources/config/buildings.yml");
        assertTrue(configFile.exists(), "buildings.yml muss unter resources/config/ liegen");
        config = YamlConfiguration.loadConfiguration(configFile);
    }

    @Test
    void dorfzentrum_hasMaxInstancesOne() {
        ConfigurationSection dorfzentrum = config.getConfigurationSection(
                "categories.general.buildings.dorfzentrum");
        assertNotNull(dorfzentrum, "Dorfzentrum-Section fehlt");

        // Wenn max_instances gesetzt ist, muss es 1 sein (nur ein Dorfzentrum pro Dorf)
        if (dorfzentrum.contains("max_instances")) {
            assertEquals(1, dorfzentrum.getInt("max_instances"),
                    "Dorfzentrum darf max 1 Mal pro Dorf gebaut werden");
        }
        // Falls nicht gesetzt, ist -1 (unbegrenzt) — ebenfalls akzeptabel,
        // weil das Dorfzentrum auto-registriert wird und nicht manuell gebaut werden kann
    }

    @Test
    void marktplatz_maxInstancesIsNotZero() {
        ConfigurationSection marktplatz = config.getConfigurationSection(
                "categories.general.buildings.marktplatz");
        assertNotNull(marktplatz, "Marktplatz-Section fehlt");

        // Falls vorhanden: Limit darf nicht 0 sein (unbrauchbar)
        int maxInstances = marktplatz.getInt("max_instances", -1);
        assertNotEquals(0, maxInstances,
                "max_instances: 0 macht ein Gebäude unbaubar – muss -1 oder >= 1 sein");
    }

    @Test
    void allBuildings_maxInstancesIsMinusOneOrPositive() {
        ConfigurationSection cats = config.getConfigurationSection("categories");
        assertNotNull(cats);

        for (String catId : cats.getKeys(false)) {
            ConfigurationSection buildings = cats.getConfigurationSection(catId + ".buildings");
            if (buildings == null) continue;
            for (String bid : buildings.getKeys(false)) {
                int maxInstances = buildings.getInt(bid + ".max_instances", -1);
                assertTrue(maxInstances == -1 || maxInstances >= 1,
                        "Gebäude '" + bid + "' hat ungültiges max_instances: " + maxInstances
                                + " (muss -1 oder >= 1 sein)");
            }
        }
    }
}

package com.example.village.building;

import org.bukkit.configuration.file.YamlConfiguration;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import java.io.File;
import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Verifiziert die Konfigurationsstruktur von quests-and-villagers.yml.
 *
 * Prüft insbesondere:
 *   - collect-items Quests haben required-items
 *   - Performance-Parameter für Villager-Ticking sind vorhanden
 *   - Kein veralteter villager-limits Block
 */
class QuestConfigTest {

    private static YamlConfiguration config;

    @BeforeAll
    static void loadConfig() {
        File configFile = new File("resources/config/quests-and-villagers.yml");
        assertTrue(configFile.exists(), "quests-and-villagers.yml muss unter resources/config/ liegen");
        config = YamlConfiguration.loadConfiguration(configFile);
    }

    // ------------------------------------------------------------------ //
    //  Collect-Items Quests                                               //
    // ------------------------------------------------------------------ //

    @Test
    void starterQuest1_hasRequiredItems() {
        assertTrue(config.contains("quests.starter-quest-1.required-items"),
                "starter-quest-1 muss required-items haben (collect-items Quest)");
        assertFalse(config.getConfigurationSection("quests.starter-quest-1.required-items")
                        .getKeys(false).isEmpty(),
                "required-items darf nicht leer sein");
    }

    @Test
    void starterQuest1_requiredItemsContainsOakLog() {
        int amount = config.getInt("quests.starter-quest-1.required-items.OAK_LOG", -1);
        assertEquals(10, amount,
                "starter-quest-1 benötigt 10x OAK_LOG");
    }

    @Test
    void farmingMission_hasRequiredItems() {
        assertTrue(config.contains("quests.farming-mission.required-items"),
                "farming-mission muss required-items haben (collect-items Quest)");
    }

    @Test
    void farmingMission_requiredItemsContainsWheat() {
        int amount = config.getInt("quests.farming-mission.required-items.WHEAT", -1);
        assertEquals(50, amount,
                "farming-mission benötigt 50x WHEAT");
    }

    @Test
    void allCollectItemsQuests_haveRequiredItems() {
        var quests = config.getConfigurationSection("quests");
        assertNotNull(quests, "quests-Sektion fehlt");
        for (String key : quests.getKeys(false)) {
            String type = quests.getString(key + ".objective-type", "");
            if ("collect-items".equals(type)) {
                assertTrue(quests.contains(key + ".required-items"),
                        "Quest '" + key + "' ist collect-items, hat aber kein required-items");
            }
        }
    }

    // ------------------------------------------------------------------ //
    //  Quest-Typen & Objective-Counts                                     //
    // ------------------------------------------------------------------ //

    @Test
    void recruitmentQuest_hasCorrectObjectiveType() {
        assertEquals("recruit-villager",
                config.getString("quests.recruitment-quest.objective-type"),
                "recruitment-quest muss objective-type: recruit-villager haben");
    }

    @Test
    void tradeQuest_isDaily() {
        assertTrue(config.getBoolean("quests.trade-quest.is-daily", false),
                "trade-quest sollte täglich (is-daily: true) sein");
    }

    @Test
    void starterQuest1_hasObjectiveCount10() {
        assertEquals(10, config.getInt("quests.starter-quest-1.objective-count"),
                "starter-quest-1 objective-count muss 10 sein");
    }

    // ------------------------------------------------------------------ //
    //  Performance-Parameter (Villager-Ticking)                           //
    // ------------------------------------------------------------------ //

    @Test
    void performanceSection_hasMaxUpdatesPerTick() {
        assertTrue(
                config.contains("performance.max-updates-per-tick")
                        || config.contains("villager-performance.max-updates-per-tick"),
                "quests-and-villagers.yml muss max-updates-per-tick unter performance oder villager-performance haben");
    }

    @Test
    void performanceSection_chunkOptimizationIsBoolean() {
        // Prüft ob der Key existiert und einen Boolean-Wert hat
        boolean found = config.contains("performance.chunk-optimization")
                || config.contains("villager-performance.chunk-optimization");
        assertTrue(found, "chunk-optimization muss konfiguriert sein");
    }

    // ------------------------------------------------------------------ //
    //  Kein veralteter villager-limits Block                              //
    // ------------------------------------------------------------------ //

    @Test
    void noLegacyVillagerLimitsSection() {
        assertFalse(config.contains("villager-limits"),
                "villager-limits ist veraltet und sollte entfernt worden sein (Konflikt mit villagers.yml base-max)");
    }
}

package com.example.village.building;

import org.bukkit.configuration.file.YamlConfiguration;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

import java.io.File;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Verifiziert die Konfiguration von light-limits.yml.
 *
 * Prüft insbesondere die neuen Parameter:
 *   - underground-max-level (Minen-Dunkelheit)
 *   - refresh-batch-size-chunks (Performance-Tuning)
 */
class LightLimitsConfigTest {

    private static YamlConfiguration config;

    @BeforeAll
    static void loadConfig() {
        File configFile = new File("resources/config/light-limits.yml");
        assertTrue(configFile.exists(), "light-limits.yml muss unter resources/config/ liegen");
        config = YamlConfiguration.loadConfiguration(configFile);
    }

    // ------------------------------------------------------------------ //
    //  underground-max-level                                              //
    // ------------------------------------------------------------------ //

    @Test
    void undergroundMaxLevel_exists() {
        assertTrue(config.contains("light-control.underground-max-level"),
                "light-limits.yml muss underground-max-level enthalten");
    }

    @Test
    void undergroundMaxLevel_isValidValue() {
        int value = config.getInt("light-control.underground-max-level", -999);
        // -999 = deaktiviert, oder ein positiver Y-Wert
        assertTrue(value == -999 || (value >= -64 && value <= 320),
                "underground-max-level muss -999 (deaktiviert) oder ein gültiges Y-Level sein, war: " + value);
    }

    @Test
    void undergroundMaxLevel_isSetTo40() {
        // Konkreter Projektwert: 40 (Y-Level unterhalb dessen Minen dunkel sind)
        assertEquals(40, config.getInt("light-control.underground-max-level"),
                "underground-max-level sollte auf 40 gesetzt sein (Minen unter Y=40 sind dunkel)");
    }

    // ------------------------------------------------------------------ //
    //  refresh-batch-size-chunks (Performance)                            //
    // ------------------------------------------------------------------ //

    @Test
    void refreshBatchSizeChunks_exists() {
        assertTrue(config.contains("light-control.refresh-batch-size-chunks"),
                "refresh-batch-size-chunks muss konfiguriert sein");
    }

    @Test
    void refreshBatchSizeChunks_isPositive() {
        int value = config.getInt("light-control.refresh-batch-size-chunks", -1);
        assertTrue(value >= 1, "refresh-batch-size-chunks muss >= 1 sein, war: " + value);
    }

    @Test
    void refreshBatchSizeChunks_isReducedForPerformance() {
        int value = config.getInt("light-control.refresh-batch-size-chunks", 8);
        // Wurde von 8 auf 4 reduziert für bessere Performance
        assertTrue(value <= 4,
                "refresh-batch-size-chunks sollte auf <= 4 reduziert worden sein, war: " + value);
    }

    // ------------------------------------------------------------------ //
    //  Basis-Konfiguration (Sanity Checks)                                //
    // ------------------------------------------------------------------ //

    @Test
    void lightControl_hasEnabledKey() {
        assertTrue(config.contains("light-control.enabled"),
                "light-control.enabled muss vorhanden sein");
    }

    @Test
    void lightControl_hasUpdateIntervalTicks() {
        assertTrue(config.contains("light-control.update-interval-ticks"),
                "update-interval-ticks muss konfiguriert sein");
        int ticks = config.getInt("light-control.update-interval-ticks");
        assertTrue(ticks >= 1, "update-interval-ticks muss >= 1 sein");
    }
}
